INSERT INTO `question_db`.`q_question` (`id`, `type`, `stem`, `difficulty`, `knowledge_point`, `analysis`, `answer`, `options_json`, `created_by`, `created_at`) VALUES (730000100001, 'SINGLE', '[JAVA-SINGLE-01] What is the main purpose of serialVersionUID?', 1, 'Serialization', 'serialVersionUID controls compatibility for serialized objects.', 'A', '[{"key": "A", "text": "Control serialization compatibility"}, {"key": "B", "text": "Configure JVM heap size"}, {"key": "C", "text": "Set thread priority"}, {"key": "D", "text": "Tune GC threshold"}]', 21001, '2026-03-15 00:13:34');
